[
  {
    "title": "Eurobarometer Data Service",
    "description": "Cross-national public opinion surveys in EU member states covering political behaviour and attitudes, trust in institutions, elections, and economic perceptions; curated and distributed by GESIS.",
    "url": "https://www.gesis.org/en/eurobarometer-data-service"
  },
  {
    "title": "ALLBUS – German General Social Survey",
    "description": "Repeated cross-sectional surveys on social and political attitudes, behaviour, and evaluations in Germany; includes measures of political participation, trust in government, and views on the economy.",
    "url": "https://www.gesis.org/en/allbus"
  },
  {
    "title": "ISSP – International Social Survey Programme",
    "description": "Annual cross-national modules such as Role of Government, Social Inequality, Citizenship, and National Identity; rich data on political attitudes, institutions, and economic policy preferences; archived by GESIS.",
    "url": "https://www.gesis.org/en/issp"
  },
  {
    "title": "GESIS Panel",
    "description": "Probability-based longitudinal panel of adults in Germany, providing high-frequency data on political behaviour, government evaluations, and economic expectations; hosted by GESIS.",
    "url": "https://www.gesis.org/en/gesis-panel"
  },
  {
    "title": "GLES – German Longitudinal Election Study",
    "description": "Comprehensive election study series for German federal elections, including pre- and post-election surveys, campaign panels, candidate studies, and rolling cross-sections; focuses on vote choice, party competition, and political attitudes; archived by GESIS.",
    "url": "https://www.gesis.org/en/gles"
  },
  {
    "title": "EVS – European Values Study",
    "description": "Multi-wave comparative survey on values and attitudes across Europe, including trust in institutions, political engagement, and economic norms; data services provided by GESIS.",
    "url": "https://www.gesis.org/en/evs"
  },
  {
    "title": "Politbarometer",
    "description": "Monthly German public opinion surveys by Forschungsgruppe Wahlen; track party support, government approval, issue salience, and economic evaluations; data archived and distributed by GESIS.",
    "url": "https://www.gesis.org/en/politbarometer"
  }
]
